type ColorValue = {
	50: string;
	100: string;
	200: string;
	300: string;
	400: string;
	500: string;
	600: string;
	700: string;
	800: string;
	900: string;
};

const sameColorRange = (color: string) => ({
	50: color,
	100: color,
	200: color,
	300: color,
	400: color,
	500: color,
	600: color,
	700: color,
	800: color,
	900: color,
});

export function getColorHexValueFromName(colorName: ColorName, appTheme?: AppTheme): string {
	if (!colorName || !colorPalette[colorName]) {
		return undefined;
	}

	const colorMap = colorPalette[colorName];

	if (!appTheme) {
		return colorMap[500];
	}

	if (appTheme.isDark) {
		return colorMap[400];
	} else {
		return colorMap[700];
	}
}

